<div class="page-header"><div><h2>Company Context Switch</h2><p>Super admins can preview tenant data and manage tenant lifecycle status without changing ownership or credentials.</p></div></div>
<div class="card"><form method="post" class="stack-form"><?= csrf_field() ?><input type="hidden" name="action" value="switch"><select name="company_id"><option value="1">Primary Company Context</option><?php foreach ($companies as $company): ?><option value="<?= e((string)$company['id']) ?>" <?= ((int)$activeCompanyId === (int)$company['id']) ? 'selected' : '' ?>><?= e($company['company_name']) ?><?= !empty($company['tenant_key']) ? ' · ' . e($company['tenant_key']) : '' ?></option><?php endforeach; ?></select><button type="submit">Switch Context</button></form></div>
<div class="card"><table><thead><tr><th>Company</th><th>Tenant Key</th><th>Status</th><th>Suspension Reason</th><th>Actions</th></tr></thead><tbody><?php foreach ($companies as $company): ?><tr><td><?= e($company['company_name']) ?></td><td><?= e((string)($company['tenant_key'] ?? '')) ?></td><td><span class="tag"><?= e((string)($company['status'] ?? 'Active')) ?></span></td><td><?= e((string)($company['suspension_reason'] ?? '')) ?></td><td><?php if (($company['status'] ?? 'Active') === 'Suspended'): ?><form method="post" style="display:inline-block"><?= csrf_field() ?><input type="hidden" name="action" value="reactivate"><input type="hidden" name="id" value="<?= e((string)$company['id']) ?>"><button type="submit">Reactivate</button></form><?php else: ?><form method="post" style="display:inline-block"><?= csrf_field() ?><input type="hidden" name="action" value="suspend"><input type="hidden" name="id" value="<?= e((string)$company['id']) ?>"><input type="text" name="reason" placeholder="Reason" value="Administrative suspension"><button type="submit">Suspend</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
